using System;
using System.Collections.Generic;
using System.IO;
using System.IO.Compression;
using System.Runtime.InteropServices;
using PaintDotNet;
using PaintDotNet.IndirectUI;
using PaintDotNet.PropertySystem;

namespace OcifPlugin
{
    internal struct CellMeta
    {
        public uint Cp;
        public byte Bg;
        public byte Fg;
        public byte Alpha;
    }

    public sealed class OcifFileTypeFactory : IFileTypeFactory2
    {
        public FileType[] GetFileTypeInstances(IFileTypeHost host)
            => new FileType[] { new OcifFileType() };
    }

    public enum PropertyNames { UseDithering, DitheringIntensity, Brightness, Contrast, Saturation, Gamma, SymbolMode, BrailleThreshold, UseMedian, ColorThreshold }
    public enum SymbolMode { Braille, SemiPixel }

    public sealed class OcifFileType : PropertyBasedFileType
    {
        // Используем обычные static поля (не ThreadStatic) чтобы данные были доступны из любого потока
        private static readonly object _lock = new object();
        private static Dictionary<(int,int),CellMeta>? _lastCells;
        private static int[] _lastPixels = Array.Empty<int>();
        private static int _lastImgW, _lastImgH;

        public OcifFileType() : base(
            "OCIF Image",
            new FileTypeOptions
            {
                LoadExtensions  = new[] { ".pic" },
                SaveExtensions  = new[] { ".pic" },
                SupportsCancellation = false,
            })
        { }

        public override PropertyCollection OnCreateSavePropertyCollection()
        {
            var props = new List<Property>
            {
                new BooleanProperty(PropertyNames.UseDithering, false),
                new DoubleProperty(PropertyNames.DitheringIntensity, 1.0, 0.0, 1.0),
                new DoubleProperty(PropertyNames.Brightness, 0.0, -1.0, 1.0),
                new DoubleProperty(PropertyNames.Contrast,   0.0, -1.0, 1.0),
                new DoubleProperty(PropertyNames.Saturation, 0.0, -1.0, 1.0),
                new StaticListChoiceProperty(PropertyNames.SymbolMode, new object[]{SymbolMode.Braille, SymbolMode.SemiPixel}, 0),
                new DoubleProperty(PropertyNames.Gamma, 1.0, 0.2, 3.0),
                new DoubleProperty(PropertyNames.BrailleThreshold, 0.5, 0.0, 1.0),
                new BooleanProperty(PropertyNames.UseMedian, false),
                new DoubleProperty(PropertyNames.ColorThreshold, 0.0, 0.0, 1.0),
            };
            var rules = new List<PropertyCollectionRule>
            {
                new ReadOnlyBoundToBooleanRule(PropertyNames.DitheringIntensity,
                    PropertyNames.UseDithering, true)
            };
            return new PropertyCollection(props, rules);
        }

        public override ControlInfo OnCreateSaveConfigUI(PropertyCollection props)
        {
            ControlInfo info = CreateDefaultSaveConfigUI(props);
            info.SetPropertyControlValue(PropertyNames.UseDithering,
                ControlInfoPropertyNames.DisplayName, "Использовать дизеринг");
            info.SetPropertyControlValue(PropertyNames.DitheringIntensity,
                ControlInfoPropertyNames.DisplayName, "Интенсивность дизеринга");
            info.FindControlForPropertyName(PropertyNames.DitheringIntensity).ControlType.Value
                = PropertyControlType.Slider;
            info.SetPropertyControlValue(PropertyNames.Brightness,
                ControlInfoPropertyNames.DisplayName, "Яркость");
            info.FindControlForPropertyName(PropertyNames.Brightness).ControlType.Value
                = PropertyControlType.Slider;
            info.SetPropertyControlValue(PropertyNames.Contrast,
                ControlInfoPropertyNames.DisplayName, "Контраст");
            info.FindControlForPropertyName(PropertyNames.Contrast).ControlType.Value
                = PropertyControlType.Slider;
            info.SetPropertyControlValue(PropertyNames.Saturation,
                ControlInfoPropertyNames.DisplayName, "Насыщенность");
            info.FindControlForPropertyName(PropertyNames.Saturation).ControlType.Value
                = PropertyControlType.Slider;
            info.SetPropertyControlValue(PropertyNames.SymbolMode,
                ControlInfoPropertyNames.DisplayName, "Режим символов");
            info.SetPropertyControlValue(PropertyNames.Gamma,
                ControlInfoPropertyNames.DisplayName, "Гамма-коррекция");
            info.FindControlForPropertyName(PropertyNames.Gamma).ControlType.Value
                = PropertyControlType.Slider;
            info.SetPropertyControlValue(PropertyNames.BrailleThreshold,
                ControlInfoPropertyNames.DisplayName, "Порог брайля (0=светлее, 1=темнее)");
            info.FindControlForPropertyName(PropertyNames.BrailleThreshold).ControlType.Value
                = PropertyControlType.Slider;
            info.SetPropertyControlValue(PropertyNames.UseMedian,
                ControlInfoPropertyNames.DisplayName, "Медианное усреднение цветов");
            info.SetPropertyControlValue(PropertyNames.ColorThreshold,
                ControlInfoPropertyNames.DisplayName, "Мин. разница цветов (0=выкл)");
            info.FindControlForPropertyName(PropertyNames.ColorThreshold).ControlType.Value
                = PropertyControlType.Slider;
            return info;
        }

        protected override Document OnLoad(Stream input)
        {
            var cells = new Dictionary<(int,int),CellMeta>();
            int[] pixels = OcifDecoder.Decode(input, out int imgW, out int imgH, cells);
            _lastCells=cells; _lastPixels=pixels; _lastImgW=imgW; _lastImgH=imgH;

            Document doc = new Document(imgW, imgH);
            BitmapLayer layer = Layer.CreateBackgroundLayer(imgW, imgH);
            unsafe
            {
                Surface surface = layer.Surface;
                for(int y=0;y<imgH;y++)
                {
                    ColorBgra* row=surface.GetRowPointerUnchecked(y);
                    for(int x=0;x<imgW;x++)
                    {
                        int argb=pixels[y*imgW+x];
                        row[x]=ColorBgra.FromBgra(
                            (byte)(argb&0xFF),(byte)((argb>>8)&0xFF),
                            (byte)((argb>>16)&0xFF),(byte)((argb>>24)&0xFF));
                    }
                }
            }
            doc.Layers.Add(layer);
            return doc;
        }

        protected override void OnSaveT(Document input, Stream output,
                                        PropertyBasedSaveConfigToken token,
                                        Surface scratchSurface,
                                        ProgressEventHandler callback)
        {
            bool   useDithering = (bool)  token.Properties[PropertyNames.UseDithering].Value!;
            double intensity    = (double)token.Properties[PropertyNames.DitheringIntensity].Value!;
            double brightness   = (double)token.Properties[PropertyNames.Brightness].Value!;
            double contrast     = (double)token.Properties[PropertyNames.Contrast].Value!;
            double saturation   = (double)token.Properties[PropertyNames.Saturation].Value!;
            var    symbolMode      = (SymbolMode)token.Properties[PropertyNames.SymbolMode].Value!;
            double gamma           = (double)token.Properties[PropertyNames.Gamma].Value!;
            double brailleThreshold= (double)token.Properties[PropertyNames.BrailleThreshold].Value!;
            bool   useMedian       = (bool)  token.Properties[PropertyNames.UseMedian].Value!;
            double colorThreshold  = (double)token.Properties[PropertyNames.ColorThreshold].Value!;
            input.Flatten(scratchSurface);
            OcifEncoder.Encode(scratchSurface, output,
                _lastCells, _lastPixels, _lastImgW, _lastImgH,
                useDithering, intensity, brightness, contrast, saturation,
                gamma, symbolMode, brailleThreshold, useMedian, colorThreshold);
        }
    }

