        private static Dictionary<uint,byte[]>? _font;
        internal static Dictionary<uint,byte[]> Font
        {
            get
            {
                if(_font==null)
                {
                    _font=new Dictionary<uint,byte[]>();
                    byte[] compressed=Convert.FromBase64String(FontB64);
                    using var ms=new MemoryStream(compressed,2,compressed.Length-2);
                    using var ds=new DeflateStream(ms,CompressionMode.Decompress);
                    using var br=new BinaryReader(ds);
                    try{while(true){
                        byte b0=br.ReadByte(),b1=br.ReadByte(),b2=br.ReadByte();
                        uint cp=(uint)((b0<<16)|(b1<<8)|b2);
                        int sz=br.ReadByte();
                        _font[cp]=br.ReadBytes(sz);
                    }}catch(EndOfStreamException){}
                }
                return _font;
            }
        }

        private static void DrawGlyph(int[] pixels,int imgW,int imgH,
                                       uint cp,int px,int py,int fg,int bg)
        {
            if(!Font.TryGetValue(cp,out byte[]? data)){FillRect(pixels,imgW,imgH,px,py,8,16,bg);return;}
            int srcW=data.Length==32?16:8;
            for(int gy=0;gy<16;gy++) for(int gx=0;gx<srcW;gx++)
            {
                int bit=(data[gy*(srcW/8)+gx/8]>>(7-gx%8))&1;
                int nx=px+gx,ny=py+gy;
                if(nx>=0&&nx<imgW&&ny>=0&&ny<imgH) pixels[ny*imgW+nx]=bit!=0?fg:bg;
            }
        }

        internal static void FillRect(int[] pixels,int imgW,int imgH,
                                      int px,int py,int w,int h,int color)
        {
            for(int dy=0;dy<h;dy++) for(int dx=0;dx<w;dx++)
            { int nx=px+dx,ny=py+dy;
              if(nx>=0&&nx<imgW&&ny>=0&&ny<imgH) pixels[ny*imgW+nx]=color; }
        }

