        private static readonly int[] BX={0,0,0,1,1,1,0,1};
        private static readonly int[] BY={0,1,2,0,1,2,3,3};

        private static int PaletteArgb(byte idx,byte alpha=255)
        {
            uint h=Palette[idx];
            return (alpha<<24)|((int)((h>>16)&0xFF)<<16)|((int)((h>>8)&0xFF)<<8)|(int)(h&0xFF);
        }

        private static uint ReadUtf8(BinaryReader r)
        {
            byte b=r.ReadByte(); int extra; uint cp;
            if((b&0x80)==0){cp=b;extra=0;}
            else if((b&0xE0)==0xC0){cp=(uint)(b&0x1F);extra=1;}
            else if((b&0xF0)==0xE0){cp=(uint)(b&0x0F);extra=2;}
            else{cp=(uint)(b&0x07);extra=3;}
            for(int i=0;i<extra;i++) cp=(cp<<6)|(uint)(r.ReadByte()&0x3F);
            return cp;
        }

        public static int[] Decode(Stream input,out int imgW,out int imgH,
                                    Dictionary<(int,int),CellMeta> cells)
        {
            using var r=new BinaryReader(input,System.Text.Encoding.UTF8,leaveOpen:true);
            byte[] sig=r.ReadBytes(4);
            if(sig[0]!='O'||sig[1]!='C'||sig[2]!='I'||sig[3]!='F')
                throw new InvalidDataException("Не OCIF файл");
            byte version=r.ReadByte();
            if(version<6||version>8) throw new InvalidDataException($"Неподдерживаемая версия ({version})");

            int add=version>=7?1:0,coordOffset=version<=7?1:0,wAdd=version==8?1:0;
            const int CHAR_W=8,CHAR_H=16;
            int W=r.ReadByte()+wAdd,H=r.ReadByte()+wAdd;
            imgW=W*CHAR_W; imgH=H*CHAR_H;
            int[] pixels=new int[imgW*imgH];
            // Инициализируем прозрачным (alpha=0) - ячейки без данных останутся прозрачными
            // Непрозрачные ячейки заполняются при рендере

            int ac=r.ReadByte()+add;
            for(int a=0;a<ac;a++)
            {
                byte al=r.ReadByte();
                int sc=(r.ReadByte()<<8|r.ReadByte())+add;
                for(int s=0;s<sc;s++)
                {
                    uint cp=ReadUtf8(r);
                    int bgc=r.ReadByte()+add;
                    for(int b=0;b<bgc;b++)
                    {
                        byte bgIdx=r.ReadByte();
                        int bg=PaletteArgb(bgIdx,(byte)(255-al));
                        int fgc=r.ReadByte()+add;
                        for(int f=0;f<fgc;f++)
                        {
                            byte fgIdx=r.ReadByte();
                            int fg=PaletteArgb(fgIdx);
                            int yc=r.ReadByte()+add;
                            for(int y=0;y<yc;y++)
                            {
                                int yp=r.ReadByte()-coordOffset;
                                int xc=r.ReadByte()+add;
                                for(int x=0;x<xc;x++)
                                {
                                    int xp=r.ReadByte()-coordOffset;
                                    int px=xp*CHAR_W,py=yp*CHAR_H;
                                    cells[(xp,yp)]=new CellMeta{Cp=cp,Bg=bgIdx,Fg=fgIdx,Alpha=al};

                                    bool isBraille=cp>=0x2801&&cp<=0x28FF;
                                    bool isSpace=cp==0x20;

                                    if(isBraille)
                                    {
                                        FillRect(pixels,imgW,imgH,px,py,CHAR_W,CHAR_H,bg);
                                        uint mask=cp-0x2800;
                                        for(int bit=0;bit<8;bit++)
                                        {
                                            int c=((mask>>bit)&1)!=0?fg:bg;
                                            for(int dy=0;dy<4;dy++) for(int dx=0;dx<4;dx++)
                                            { int nx=px+BX[bit]*4+dx,ny=py+BY[bit]*4+dy;
                                              if(nx>=0&&nx<imgW&&ny>=0&&ny<imgH) pixels[ny*imgW+nx]=c; }
                                        }
                                    }
                                    else if(isSpace)
                                        FillRect(pixels,imgW,imgH,px,py,CHAR_W,CHAR_H,bg);
                                    else
                                        DrawGlyph(pixels,imgW,imgH,cp,px,py,fg,bg);
                                }
                            }
                        }
                    }
                }
            }
            return pixels;
        }
    }

    // ════════════════════════════════════════════════════════════════════════
    //  ЭНКОДЕР
    // ════════════════════════════════════════════════════════════════════════
    internal static class OcifEncoder
    {
        internal static readonly uint[] Palette = OcifDecoder.Palette;

        // Найти ближайший цвет в палитре, вернуть индекс
        private static byte NearestIdx(double r,double g,double b)
        {
            int best=0; double bestDist=double.MaxValue;
            for(int i=0;i<Palette.Length;i++)
            {
                uint h=Palette[i];
                double dr=r-((h>>16)&0xFF), dg=g-((h>>8)&0xFF), db=b-(h&0xFF);
                double d=dr*dr+dg*dg+db*db;
                if(d<bestDist){bestDist=d;best=i;}
            }
            return (byte)best;
        }

        private static double ColorDist(double r1,double g1,double b1,
                                         double r2,double g2,double b2)
        {
            double dr=r1-r2,dg=g1-g2,db=b1-b2;
            return dr*dr+dg*dg+db*db;
        }

        private static double ColorDist(double r1,double g1,double b1,uint h2)
        {
            double dr=r1-((h2>>16)&0xFF),dg=g1-((h2>>8)&0xFF),db=b1-(h2&0xFF);
            return dr*dr+dg*dg+db*db;
        }

        private static unsafe bool CellChanged(Surface surface,int px,int py,
                                                int[] origPixels,int imgW,int imgH)
        {
            for(int dy=0;dy<16;dy++) for(int dx=0;dx<8;dx++)
            {
                int nx=px+dx,ny=py+dy;
                if(nx<0||nx>=imgW||ny<0||ny>=imgH) continue;
                ColorBgra* p=surface.GetPointPointerUnchecked(nx,ny);
                // Сравниваем только RGB — игнорируем alpha
                // (origPixels может иметь alpha=0 для чёрного фона,
                //  а surface после Flatten имеет alpha=255)
                int surfRGB=(p->R<<16)|(p->G<<8)|p->B;
                int origArgb=(ny*imgW+nx<origPixels.Length)?origPixels[ny*imgW+nx]:0;
                int origRGB=(origArgb>>16&0xFF)<<16|(origArgb>>8&0xFF)<<8|(origArgb&0xFF);
                if(surfRGB!=origRGB) return true;
            }
            return false;
        }

        private static uint BrailleCp(bool[] dot)
        {
            // dot[bit]: BX={0,0,0,1,1,1,0,1}, BY={0,1,2,0,1,2,3,3}
            // braille bit mapping
            int[] BX={0,0,0,1,1,1,0,1},BY={0,1,2,0,1,2,3,3};
            uint mask=0;
            for(int bit=0;bit<8;bit++)
                if(dot[BY[bit]*2+BX[bit]]) mask|=(1u<<bit);
            return 0x2800+mask; // U+2800 = пустой брайль (все точки = bg)
        }

        private static void WriteUtf8(BinaryWriter w,uint cp)
        {
            if(cp<0x80) w.Write((byte)cp);
            else if(cp<0x800){w.Write((byte)(0xC0|(cp>>6)));w.Write((byte)(0x80|(cp&0x3F)));}
            else if(cp<0x10000){w.Write((byte)(0xE0|(cp>>12)));w.Write((byte)(0x80|((cp>>6)&0x3F)));w.Write((byte)(0x80|(cp&0x3F)));}
            else{w.Write((byte)(0xF0|(cp>>18)));w.Write((byte)(0x80|((cp>>12)&0x3F)));w.Write((byte)(0x80|((cp>>6)&0x3F)));w.Write((byte)(0x80|(cp&0x3F)));}
        }

        // Применяем яркость/контраст/насыщенность к каналам R,G,B
        private static void ApplyBCS(ref double r, ref double g, ref double b,
                                      double brightness, double contrast, double saturation)
        {
            // Яркость: сдвиг [-1..1] -> [-255..255]
            r += brightness * 255;
            g += brightness * 255;
            b += brightness * 255;

            // Контраст: factor от 0.0 до 4.0 (0.0 = серый, 1.0 = без изменений)
            double cf = (1.0 + contrast * 2.0);
            r = (r - 128) * cf + 128;
            g = (g - 128) * cf + 128;
            b = (b - 128) * cf + 128;

            // Насыщенность: через luminance
            double lum = 0.2126 * r + 0.7152 * g + 0.0722 * b;
            double sf = 1.0 + saturation * 2.0;
            r = lum + (r - lum) * sf;
            g = lum + (g - lum) * sf;
            b = lum + (b - lum) * sf;

            // Клампируем
            r = Math.Max(0, Math.Min(255, r));
            g = Math.Max(0, Math.Min(255, g));
            b = Math.Max(0, Math.Min(255, b));
        }

        public static unsafe void Encode(Surface surface,Stream output,
                                          Dictionary<(int,int),CellMeta>? origCells,
                                          int[] origPixels,int origImgW,int origImgH,
                                          bool useDithering,double intensity,
                                          double brightness,double contrast,double saturation,
                                          double gamma,SymbolMode symbolMode,
                                          double brailleThreshold,bool useMedian,double colorThreshold)
        {
            const int CHAR_W=8,CHAR_H=16;
            // OCIF символ = 2x4 пикселя, но у нас рендер 8x16
            // Поэтому каждый OCIF-пиксель = блок 4x4 в нашем surface
            // Дизеринг делаем на уровне OCIF-пикселей (блоков 4x4)
            // Размер в OCIF-пикселях:
            int W=surface.Width/CHAR_W,H=surface.Height/CHAR_H;
            // OCIF-пиксели: OW = W*2, OH = H*4
            int OW=W*2,OH=H*4;
            if(W==0||H==0) return;

            // Буфер OCIF-пикселей с накопленной ошибкой дизеринга
            double[] oR=new double[OW*OH];
            double[] oG=new double[OW*OH];
            double[] oB=new double[OW*OH];
            byte[]   oA=new byte[OW*OH];   // 0=прозрачный

            // Заполняем буфер OCIF-пикселей из surface
            // Каждый OCIF-пиксель = блок 4x4 реальных пикселей
            // oA=1 если блок непрозрачный, oA=0 если прозрачный
            for(int oy=0;oy<OH;oy++)
            for(int ox=0;ox<OW;ox++)
            {
                int px=ox*4,py=oy*4;
                double sr=0,sg=0,sb=0;
                int opaqueCnt=0, totalCnt=0;
                for(int dy=0;dy<4;dy++) for(int dx=0;dx<4;dx++)
                {
                    int nx=px+dx,ny=py+dy;
                    if(nx>=surface.Width||ny>=surface.Height) continue;
                    totalCnt++;
                    ColorBgra* p=surface.GetPointPointerUnchecked(nx,ny);
                    if(p->A>=128) { sr+=p->R; sg+=p->G; sb+=p->B; opaqueCnt++; }
                }
                if(opaqueCnt>0)
                {
                    double pr=sr/opaqueCnt,pg=sg/opaqueCnt,pb=sb/opaqueCnt;
                    ApplyBCS(ref pr,ref pg,ref pb,brightness,contrast,saturation);
                    if(gamma!=1.0)
                    {
                        pr=Math.Pow(pr/255.0,1.0/gamma)*255.0;
                        pg=Math.Pow(pg/255.0,1.0/gamma)*255.0;
                        pb=Math.Pow(pb/255.0,1.0/gamma)*255.0;
                    }
                    oR[oy*OW+ox]=Math.Max(0,Math.Min(255,pr));
                    oG[oy*OW+ox]=Math.Max(0,Math.Min(255,pg));
                    oB[oy*OW+ox]=Math.Max(0,Math.Min(255,pb));
                    oA[oy*OW+ox]=1; // непрозрачный
                }
                // иначе oA=0 = прозрачный OCIF-пиксель
            }

            // Floyd-Steinberg дизеринг на OCIF-пикселях
            if(useDithering)
            {
                for(int oy=0;oy<OH;oy++)
                for(int ox=0;ox<OW;ox++)
                {
                    if(oA[oy*OW+ox]==0) continue;
                    double r=oR[oy*OW+ox],g=oG[oy*OW+ox],b=oB[oy*OW+ox];
                    // Клампируем
                    r=Math.Max(0,Math.Min(255,r));
                    g=Math.Max(0,Math.Min(255,g));
                    b=Math.Max(0,Math.Min(255,b));
                    byte idx=NearestIdx(r,g,b);
                    uint h=Palette[idx];
                    double pr=(h>>16)&0xFF,pg=(h>>8)&0xFF,pb=h&0xFF;
                    double er=(r-pr)*intensity,eg=(g-pg)*intensity,eb=(b-pb)*intensity;
                    oR[oy*OW+ox]=pr; oG[oy*OW+ox]=pg; oB[oy*OW+ox]=pb;
                    // Распределяем ошибку: 7/16, 3/16, 5/16, 1/16
                    if(ox+1<OW){oR[oy*OW+ox+1]+=er*7/16;oG[oy*OW+ox+1]+=eg*7/16;oB[oy*OW+ox+1]+=eb*7/16;}
                    if(oy+1<OH)
                    {
                        if(ox-1>=0){oR[(oy+1)*OW+ox-1]+=er*3/16;oG[(oy+1)*OW+ox-1]+=eg*3/16;oB[(oy+1)*OW+ox-1]+=eb*3/16;}
                        oR[(oy+1)*OW+ox]+=er*5/16;oG[(oy+1)*OW+ox]+=eg*5/16;oB[(oy+1)*OW+ox]+=eb*5/16;
                        if(ox+1<OW){oR[(oy+1)*OW+ox+1]+=er*1/16;oG[(oy+1)*OW+ox+1]+=eg*1/16;oB[(oy+1)*OW+ox+1]+=eb*1/16;}
                    }
                }
            }

            // Собираем ячейки OCIF
            var grouped=new SortedDictionary<byte,
                SortedDictionary<uint,
                SortedDictionary<byte,
                SortedDictionary<byte,
                SortedDictionary<byte,List<byte>>>>>>();

            for(int cy=0;cy<H;cy++)
            for(int cx=0;cx<W;cx++)
            {
                int px=cx*CHAR_W,py=cy*CHAR_H;

                // Считаем прозрачные OCIF-пиксели в ячейке
                int transCnt=0;
                for(int oy=cy*4;oy<cy*4+4;oy++) for(int ox=cx*2;ox<cx*2+2;ox++)
                    if(oA[oy*OW+ox]==0) transCnt++;
                if(transCnt==8)
                {
                    // Все 8 точек прозрачные — записываем U+2800 al=255 (прозрачный bg)
                    // Это необходимо для корректного отображения в OC
                    byte alT=255, bgT=0, fgT=0; uint cpT=0x2800;
                    if(!grouped.ContainsKey(alT)) grouped[alT]=new SortedDictionary<uint,SortedDictionary<byte,SortedDictionary<byte,SortedDictionary<byte,List<byte>>>>>();
                    if(!grouped[alT].ContainsKey(cpT)) grouped[alT][cpT]=new SortedDictionary<byte,SortedDictionary<byte,SortedDictionary<byte,List<byte>>>>();
                    if(!grouped[alT][cpT].ContainsKey(bgT)) grouped[alT][cpT][bgT]=new SortedDictionary<byte,SortedDictionary<byte,List<byte>>>();
                    if(!grouped[alT][cpT][bgT].ContainsKey(fgT)) grouped[alT][cpT][bgT][fgT]=new SortedDictionary<byte,List<byte>>();
                    if(!grouped[alT][cpT][bgT][fgT].ContainsKey((byte)cy)) grouped[alT][cpT][bgT][fgT][(byte)cy]=new List<byte>();
                    grouped[alT][cpT][bgT][fgT][(byte)cy].Add((byte)cx);
                    continue;
                }

                uint cp; byte bgIdx,fgIdx,alpha=0;

                if(symbolMode==SymbolMode.SemiPixel)
                {
                    // Полупиксели: верхний пиксель ячейки = bg, нижний = fg через символ ▄
                    // Каждый OCIF-пиксель по высоте = 2 строки (oy=cy*4 верх, cy*4+2 низ)
                    // Усредняем верхнюю половину (строки 0,1) и нижнюю (строки 2,3)
                    double topR=0,topG=0,topB=0; int topCnt=0;
                    double botR=0,botG=0,botB=0; int botCnt=0;
                    for(int oy=cy*4;oy<cy*4+2;oy++) for(int ox=cx*2;ox<cx*2+2;ox++)
                    { if(oA[oy*OW+ox]==0) continue;
                      topR+=oR[oy*OW+ox];topG+=oG[oy*OW+ox];topB+=oB[oy*OW+ox];topCnt++; }
                    for(int oy=cy*4+2;oy<cy*4+4;oy++) for(int ox=cx*2;ox<cx*2+2;ox++)
                    { if(oA[oy*OW+ox]==0) continue;
                      botR+=oR[oy*OW+ox];botG+=oG[oy*OW+ox];botB+=oB[oy*OW+ox];botCnt++; }
                    if(topCnt==0&&botCnt==0) continue;
                    if(topCnt==0){topR=botR/botCnt;topG=botG/botCnt;topB=botB/botCnt;}
                    else{topR/=topCnt;topG/=topCnt;topB/=topCnt;}
                    if(botCnt==0){botR=topR;botG=topG;botB=topB;}
                    else{botR/=botCnt;botG/=botCnt;botB/=botCnt;}
                    bgIdx=NearestIdx(topR,topG,topB); // bg = верх
                    fgIdx=NearestIdx(botR,botG,botB); // fg = низ через ▄
                    cp=0x2584; // ▄
                }
                else
                {
                    // Брайль — правильная логика с прозрачностью на уровне точек
                    int[] BX2={0,0,0,1,1,1,0,1},BY2={0,1,2,0,1,2,3,3};
                    double[] cr=new double[8],cg=new double[8],cb=new double[8];
                    byte[] ca=new byte[8];
                    for(int bit=0;bit<8;bit++)
                    {
                        int ox=cx*2+BX2[bit],oy=cy*4+BY2[bit];
                        cr[bit]=Math.Max(0,Math.Min(255,oR[oy*OW+ox]));
                        cg[bit]=Math.Max(0,Math.Min(255,oG[oy*OW+ox]));
                        cb[bit]=Math.Max(0,Math.Min(255,oB[oy*OW+ox]));
                        ca[bit]=oA[oy*OW+ox];
                    }

                    // Есть ли прозрачные точки?
                    bool hasTransparentDots = false;
                    for(int bit=0;bit<8;bit++) if(ca[bit]==0){ hasTransparentDots=true; break; }

                    if(hasTransparentDots)
                    {
                        // Есть прозрачные точки → bg прозрачный (alpha=255 в OCIF)
                        // fg = усреднённый цвет непрозрачных точек
                        alpha=255; // прозрачный bg
                        double sumR=0,sumG=0,sumB=0; int cnt=0;
                        for(int bit=0;bit<8;bit++)
                            if(ca[bit]!=0){sumR+=cr[bit];sumG+=cg[bit];sumB+=cb[bit];cnt++;}
                        if(cnt==0){bgIdx=0;fgIdx=0;cp=0x2800;} // U+2800 = пустой брайль с прозрачным фоном
                        else
                        {
                            bgIdx=0; // чёрный прозрачный bg (индекс 0 = 0x000000)
                            fgIdx=NearestIdx(sumR/cnt,sumG/cnt,sumB/cnt);
                            // Прозрачные точки → bg(0), непрозрачные → fg(1)
                            bool[] dot=new bool[8];
                            for(int bit=0;bit<8;bit++)
                                dot[BY2[bit]*2+BX2[bit]]=(ca[bit]!=0);
                            cp=BrailleCp(dot);
                        }
                    }
                    else
                    {
                        // Все точки непрозрачные — обычная логика
                        alpha=0;
                        var lumList=new System.Collections.Generic.List<(double lum,int idx)>();
                        for(int bit=0;bit<8;bit++)
                        {
                            double lum=cr[bit]*cr[bit]+cg[bit]*cg[bit]+cb[bit]*cb[bit];
                            lumList.Add((lum,bit));
                        }

                        int minIdx=lumList[0].idx, maxIdx=lumList[0].idx;
                        double minLum=lumList[0].lum, maxLum=lumList[0].lum;
                        for(int i=1;i<8;i++)
                        {
                            if(lumList[i].lum<minLum){minLum=lumList[i].lum;minIdx=lumList[i].idx;}
                            if(lumList[i].lum>maxLum){maxLum=lumList[i].lum;maxIdx=lumList[i].idx;}
                        }

                        if(useMedian)
                        {
                            lumList.Sort((a,b2)=>a.lum.CompareTo(b2.lum));
                            int q=Math.Max(1,8/4);
                            double sumBgR=0,sumBgG=0,sumBgB=0;
                            double sumFgR=0,sumFgG=0,sumFgB=0;
                            for(int i=0;i<q;i++){sumBgR+=cr[lumList[i].idx];sumBgG+=cg[lumList[i].idx];sumBgB+=cb[lumList[i].idx];}
                            for(int i=8-q;i<8;i++){sumFgR+=cr[lumList[i].idx];sumFgG+=cg[lumList[i].idx];sumFgB+=cb[lumList[i].idx];}
                            bgIdx=NearestIdx(sumBgR/q,sumBgG/q,sumBgB/q);
                            fgIdx=NearestIdx(sumFgR/q,sumFgG/q,sumFgB/q);
                        }
                        else
                        {
                            bgIdx=NearestIdx(cr[minIdx],cg[minIdx],cb[minIdx]);
                            fgIdx=NearestIdx(cr[maxIdx],cg[maxIdx],cb[maxIdx]);
                        }

                        double bgR=(Palette[bgIdx]>>16)&0xFF,bgG2=(Palette[bgIdx]>>8)&0xFF,bgB=(Palette[bgIdx])&0xFF;
                        double fgR=(Palette[fgIdx]>>16)&0xFF,fgG2=(Palette[fgIdx]>>8)&0xFF,fgB=(Palette[fgIdx])&0xFF;
                        double colorDiff=Math.Sqrt(ColorDist(bgR,bgG2,bgB,fgR,fgG2,fgB))/441.67;
                        if(colorThreshold>0 && colorDiff<colorThreshold)
                        {
                            bgIdx=NearestIdx((bgR+fgR)/2,(bgG2+fgG2)/2,(bgB+fgB)/2);
                            fgIdx=bgIdx; cp=0x20;
                        }
                        else
                        {
                            bool[] dot=new bool[8];
                            for(int bit=0;bit<8;bit++)
                            {
                                double dBg=ColorDist(cr[bit],cg[bit],cb[bit],bgR,bgG2,bgB);
                                double dFg=ColorDist(cr[bit],cg[bit],cb[bit],fgR,fgG2,fgB);
                                dot[BY2[bit]*2+BX2[bit]]=dFg/(dBg+dFg+1e-10)<brailleThreshold;
                            }
                            cp=BrailleCp(dot);
                        }
                    }
                }

                if(!grouped.ContainsKey(alpha))
                    grouped[alpha]=new SortedDictionary<uint,SortedDictionary<byte,SortedDictionary<byte,SortedDictionary<byte,List<byte>>>>>();
                if(!grouped[alpha].ContainsKey(cp))
                    grouped[alpha][cp]=new SortedDictionary<byte,SortedDictionary<byte,SortedDictionary<byte,List<byte>>>>();
                if(!grouped[alpha][cp].ContainsKey(bgIdx))
                    grouped[alpha][cp][bgIdx]=new SortedDictionary<byte,SortedDictionary<byte,List<byte>>>();
                if(!grouped[alpha][cp][bgIdx].ContainsKey(fgIdx))
                    grouped[alpha][cp][bgIdx][fgIdx]=new SortedDictionary<byte,List<byte>>();
                if(!grouped[alpha][cp][bgIdx][fgIdx].ContainsKey((byte)cy))
                    grouped[alpha][cp][bgIdx][fgIdx][(byte)cy]=new List<byte>();
                grouped[alpha][cp][bgIdx][fgIdx][(byte)cy].Add((byte)cx);
            }

            using var w=new BinaryWriter(output,System.Text.Encoding.UTF8,leaveOpen:true);
            w.Write(new byte[]{(byte)'O',(byte)'C',(byte)'I',(byte)'F'});
            w.Write((byte)8);
            w.Write((byte)(W-1));
            w.Write((byte)(H-1));
            w.Write((byte)(grouped.Count-1));

            foreach(var (al,chars) in grouped)
            {
                w.Write(al);
                w.Write((byte)((chars.Count-1)>>8));
                w.Write((byte)((chars.Count-1)&0xFF));
                foreach(var (cp2,bgs) in chars)
                {
                    WriteUtf8(w,cp2);
                    w.Write((byte)(bgs.Count-1));
                    foreach(var (bg2,fgs) in bgs)
                    {
                        w.Write(bg2);
                        w.Write((byte)(fgs.Count-1));
                        foreach(var (fg2,ys) in fgs)
                        {
                            w.Write(fg2);
                            w.Write((byte)(ys.Count-1));
                            foreach(var (y2,xs) in ys)
                            {
                                w.Write(y2);
                                w.Write((byte)(xs.Count-1));
                                foreach(var x2 in xs) w.Write(x2);
                            }
                        }
                    }
                }
            }
        }
    }
}
